mapper.select:
SELECT s.id, s.part_name, s.part_code, s.model_id, s.warehouse_id, s.status, s.quantity, s.create_time, m.model_name, w.warehouse_name FROM spare_part s LEFT JOIN device_model m ON m.id = s.model_id AND m.deleted = 0 LEFT JOIN warehouse w ON w.id = s.warehouse_id AND w.deleted = 0
s.deleted = 0
AND (s.part_name LIKE CONCAT('%', #{keyword}, '%') OR s.part_code LIKE CONCAT('%', #{keyword}, '%'))
AND s.warehouse_id = #{warehouseId}
AND s.model_id = #{modelId}
ORDER BY s.create_time DESC, s.id DESC
